module top_module(input wire clk, vgae2, 
                input wire [7:0] e,
                output wire [3:0] num);reg [3:0] invalid_output;

  always @(e, vgae2) 
  begin
    if (vgae2) 
    begin
      case (e[3:0])              
        4'b0000: invalid_output = 0;
        4'b0001: invalid_output = 1;
        4'b0010: invalid_output = 2;
        4'b0011: invalid_output = 3;
        4'b0100: invalid_output = 4;
        4'b0101: invalid_output = 5;
        4'b0110: invalid_output = 6;
        4'b0111: invalid_output = 7;
        4'b1000: invalid_output = 8;
        4'b1001: invalid_output = 9;
        default: invalid_output = 15;  
      endcase
    end      
  end

  assign num = invalid_output;

endmodule
